  ('bookkeeper-moex-01818', 'bookkeeper', 'bookkeeper-moex-100-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '關於股份有限公司主辦會計人員之任免，其法定應執行程序為：', '["應由董事會以董事過半數之出席，及出席董事過半數之同意", "應有全體股東過半數之同意", "應有全體無限責任股東過半數之同意", "應有全體股東三分之二以上之同意"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "b74f913e06f7", "answer_pdf_sha1": "79fc2cc5e98c", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01819', 'bookkeeper', 'bookkeeper-moex-100-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '未依法取得代他人處理會計事務之資格而擅自代他人處理商業會計事務，經查獲後三年內再犯者，應如 何處罰？', '["處新臺幣10萬元以下罰金", "處1年以下有期徒刑、拘役或科或併科新臺幣15萬元以下罰金", "處新臺幣6萬元以上30萬元以下罰鍰", "處5年以下有期徒刑、拘役或科或併科新臺幣60萬元以下罰金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "b74f913e06f7", "answer_pdf_sha1": "79fc2cc5e98c", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01820', 'bookkeeper', 'bookkeeper-moex-100-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '下列何者係屬行政程序法第92條規定之行政處分？①國稅局對營業人漏開發票者科處罰鍰  ②行政機關', '["交通部中央氣象局提供氣候的相關資訊及氣象報導", "政府役政機關對役男兵役體位 之判定  ⑤財政部所頒布之稅務違章案件減免處罰標準  ⑥稅捐稽徵機關核發課稅通知書  警察對道 路交通違規者開立的罰單  監理機關與民間某修車廠簽約，將汽車檢驗權限委託其行使  臺中市政 府就某建築指定為古蹟", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "b74f913e06f7", "answer_pdf_sha1": "79fc2cc5e98c", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
  ('bookkeeper-moex-01821', 'bookkeeper', 'bookkeeper-moex-100-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '行政機關作成行政處分時，處分機關未告知救濟期間或告知之救濟期間有錯誤時，依行政程序法第98條 規定，相對人或利害關係人提起救濟效力，下列何者錯誤？', '["未告知救濟期間者，行政處分無效", "通知更正，自通知送達之翌日起算法定期間", "通知更正，但信賴原告知較長期間，於原告知之期間內為之者，視為於法定期間內所為", "告知錯誤未為更正，致遲誤原時間者，自處分書送達後一年內聲明不服時，視為於法定期間內所為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:28+00:00", "source_pdf_sha1": "b74f913e06f7", "answer_pdf_sha1": "79fc2cc5e98c", "source_family": "moex-gov-tw", "moex": {"exam_code": "100230", "c": "602", "s": "1101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "100", "exam_name": "100年專技人員高考建築師、技師、第2次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL)
